  // const runnerRef = useRef(null);     // Reference to the Matter.js runner, which manages the timing and execution of the physics simulation, allowing us to start, stop, or adjust the simulation as necessary during gameplay.


  const Striker_Catagory = 0x0002;      // Define a collision category for the striker to control how it interacts with other bodies in the physics simulation. By assigning a unique category value to the striker, we can specify which other categories of bodies it can collide with, allowing us to manage the interactions between the striker and the coins on the carrom board during gameplay. This categorization helps us implement game logic based on collisions, such as scoring points when the striker hits certain coins or pockets, enhancing the overall functionality and interactivity of the carrom game.
